import jibo = require('jibo');
import Router = require('router');
import { JiboServerRequest, JiboServerResponse, ServiceOptions, HTTPService } from 'jibo-service-framework';
import * as jetstream from '@jibo/jetstream-client';

export class SingletonEnforcer{}

/**
 * Request parameters to the Context Service.
 * @interface ContextParams
 * @prop {jibo.jetstream.types.HubSpeakerRecogResults} [speakers] - List of speakers we've confidently ID'd and want inserted into the response.
 * @prop {boolean} [omitLoop] - Whether or not `users` and `jibo` should be excluded from the Context response.
 */
interface ContextParams {
    speakers?: jetstream.types.HubSpeakerRecogResults;
    omitLoop?: boolean;
}


/**
 * @description
 * Service endpoint which exposes on-robot context data to those outside Be.
 *
 * @class ContextService
 * @extends HTTPService
 */
export class ContextService extends HTTPService {

    private static _instance: ContextService;

    public static createInstance(options: ServiceOptions, rootDir?: string): ContextService {
        return new ContextService(new SingletonEnforcer(), options, rootDir);
    }

    public static get instance(): ContextService {
        return ContextService._instance;
    }

    constructor(enforcer: SingletonEnforcer, options: ServiceOptions, rootDir?: string) {
        super('context', options, rootDir);
        if (ContextService._instance) {
            throw new Error('ContextService is a singleton');
        }
        ContextService._instance = this;
    }

    routes(url: Router) {
        super.routes(url);
        url.post('/context', async (req:JiboServerRequest, res:JiboServerResponse) => {
            this.getContext(req, res);
        });
    }

    private async getContext(req: JiboServerRequest, res: JiboServerResponse): Promise<void> {
        let speakers: jetstream.types.HubSpeakerRecogResults = null;
        let omitLoop = false;

        const params: ContextParams = req.body;

        try {
            if (params) {
                const valid = ((params instanceof Object) && !Array.isArray(params));
                if (!valid) {
                    return this.sendJson(res, { error: `Supplied parameters are malformed.` }, 500);
                }

                if (params.hasOwnProperty('speakers')) {
                    if (Array.isArray(params.speakers.accepted)) {
                        speakers = params.speakers;
                    } else {
                        return this.sendJson(res, { error: `Supplied 'speakers' parameter is invalid.` }, 500);
                    }
                }
                if (params.hasOwnProperty('omitLoop')) {
                    if (typeof params.omitLoop === 'boolean') {
                        omitLoop = params.omitLoop;
                    } else {
                        return this.sendJson(res, { error: `Supplied 'omitLoop' parameter is invalid.` }, 500);
                    }
                }
            }
        } catch (e) {
            return this.sendJson(res, { error: `Unable to process supplied parameters: ${e.message}` }, 500);
        }

        try {
            const data = await jibo.context.getContext(speakers, omitLoop);
            this.sendJson(res, data);
        } catch (err) {
            this.sendJson(res, {
                error: `Unable to retrieve robot context: ${err.message}`
            }, 500);
        }
    }
}