import jibo = require('jibo');
import BeSkill from '../../BeSkill';

BeSkill.registerOpenHook((oldSkill, newSkill, result) => {
    return (resolve, reject) => {
        return jibo.expression.setAttentionMode(jibo.expression.AttentionMode.ENGAGED)
            .then(resolve)
            .catch(reject);
    };
});
