import jibo = require('jibo');
import { PromiseUtils } from 'jibo-cai-utils';
import BeSkill from '../../BeSkill';
import { ContextService } from './ContextService';

import parentLog from '../../log';
const log = parentLog.createChild('ContextServiceBeSkillPlugin');

const prify = PromiseUtils.promisify;

/*
 * Registers service endpoint which exposes on-robot context data to those outside Be.
 */
BeSkill.registerPlugin('context', async (resolve, reject) => {

    const port = (jibo.runMode === jibo.RunMode.ON_ROBOT) ? 8588 : 0;
    const contextService = ContextService.createInstance({ port: port, register: true });

    try {
        await prify(h => contextService.init(h));
        log.info(`Successfully initialized ContextService`);
        resolve(ContextService.instance);
    } catch (err) {
        log.error(`Could not initialize ContextService`);
        reject(err);
    }
});
