import BeSkill from '../../BeSkill';
import PackageUtils from '../../utils/PackageUtils';
import jibo = require('jibo');

/**
 * Class for the on-screen timer.
 * @class Timer
 */

class Timer {

    private _updateBind = this.update.bind(this);
    private _text: PIXI.Text;
    private _running = false;

    constructor() {
        this._text = new PIXI.Text('', {
            fontFamily:'Lucida Grande',
            fontSize: 80,
            fontWeight: 'bold',
            fill: '#AA0404',
            align: 'right'
        });
    }

    /**
     * `true` if timer is running.
     * @method Timer.isRunning
     * @type {boolean}
     */
    isRunning(): boolean {
        return this._running;
    }

    /**
     * Start the timer.
     * @method Timer.start
     */
    start() {
        if (!this._running) {
            this._running = true;
            jibo.timer.on('update', this._updateBind);
            jibo.face.stage.addChild(this._text);
        }
    }

    /**
     * Stop the timer.
     * @method Timer.stop
     */
    stop() {
        if (this._running) {
            this._running = false;
            jibo.timer.removeListener('update', this._updateBind);
            jibo.face.stage.removeChild(this._text);
        }
    }

    /**
     * Update the timer.
     * @method Timer.update
     * @param delta {number}
     */
    update(delta) {
        let date = new Date(Date.now());
        let formattedDate = `${date.getHours()}:${date.getMinutes()}:${date.getSeconds()}:${date.getMilliseconds()}`;
        this._text.text = formattedDate;
    }
}

BeSkill.registerPlugin('onScreenTimer', (resolve, reject) => {
    try {
        const timer = new Timer();
        if (PackageUtils.debugMode('showTimer')) {
            timer.start();
        }
        resolve(timer);
    }
    catch (error) {
        reject(`Error when loading OnScreenTimer plugin: ${error}`);
    }
});
